A debounce function limits the rate at which a function is executed. Here's a small JavaScript debounce function with an example:

function debounce(callback, delay) {
  let timeout;
  return function () {
    const context = this;
    const args = arguments;
    const later = function () {
      callback.apply(context, args);
    };
    clearTimeout(timeout);
    timeout = setTimeout(later, delay);
  };}

// Example usage:
const debouncedButton_Click_aster_proper_WriteButton = debounce(function(event) {
  console.log('Button clicked after debounce delay');
}, 500);

const button = document.getElementById('myButton'); 
button.addEventListener('click', debouncedButton_Click_aster_proper_WriteButton);

